matrix = [[1, 2, 3], [4, 5, 6], [7, 8, 9]]
print('Sorted Array:', bubble_sort(array))
print('Diagonal Sum:', diagonal_sum(matrix))
# Çıxış: Sorted Array: [1, 2, 5, 8, 9]
# Çıxış: Diagonal Sum: 15

