#include <stdio.h>
#include <stdlib.h>

void bubbleSort(int arr[], int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                int temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }
}

int diagonalSum(int matrix[][3], int n) {
    int total = 0;
    for (int i = 0; i < n; i++) {
        total += matrix[i][i];
    }
    return total;
}

int main() {
    int array[] = {5, 2, 8, 1, 9};
    int matrix[3][3] = {{1, 2, 3}, {4, 5, 6}, {7, 8, 9}};
