    bubbleSort(array, n);
    printf("Sorted Array: [");
    for (int i = 0; i < n; i++) {
        printf("%d", array[i]);
        if (i < n - 1) printf(", ");
    }
    printf("]\n");
    printf("Diagonal Sum: %d\n", diagonalSum(matrix, 3));
    return 0;
}
// Çıxış: Sorted Array: [1, 2, 5, 8, 9]
