#include <iostream>
#include <vector>

std::vector<int> bubbleSort(std::vector<int> arr) {
    int n = arr.size();
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                std::swap(arr[j], arr[j + 1]);
            }
        }
    }
    return arr;
}

int diagonalSum(const std::vector<std::vector<int>>& matrix) {
    int total = 0;
    for (size_t i = 0; i < matrix.size(); i++) {
        total += matrix[i][i];
    }
    return total;
}

