    std::vector<int> array = {5, 2, 8, 1, 9};
    std::vector<std::vector<int>> matrix = {{1, 2, 3}, {4, 5, 6}, {7, 8, 9}};
    array = bubbleSort(array);
    std::cout << "Sorted Array: [";
    for (size_t i = 0; i < array.size(); i++) {
        std::cout << array[i];
        if (i < array.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    std::cout << "Diagonal Sum: " << diagonalSum(matrix) << "\n";
    return 0;
}
// Çıxış: Sorted Array: [1, 2, 5, 8, 9]
// Çıxış: Diagonal Sum: 15

